using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(IHttpClientFactory httpClientFactory, ILogger<ApiTools> logger)
{
    private HttpClient CreateClient() => httpClientFactory.CreateClient("api");

    [McpServerTool, Description("Get a list of posts, optionally filtered by user ID.")]
    public async Task<string> GetPosts(
        [Description("Filter posts by this user ID (optional)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var client = CreateClient();
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Fetching posts from {Url}", url);
        return await client.GetStringAsync(url, cancellationToken);
    }

    [McpServerTool, Description("Get a single post by its ID.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        var client = CreateClient();
        logger.LogInformation("Fetching post {Id}", id);
        var response = await client.GetAsync($"/posts/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new post.")]
    public async Task<string> CreatePost(
        [Description("Title of the new post")] string title,
        [Description("Body content of the new post")] string body,
        [Description("User ID of the post author")] int userId,
        CancellationToken cancellationToken = default)
    {
        var client = CreateClient();
        var payload = JsonSerializer.Serialize(new { title, body, userId });
        logger.LogInformation("Creating post for user {UserId}", userId);

        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");
        var response = await client.PostAsync("/posts", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get all comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to get comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        var client = CreateClient();
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        return await client.GetStringAsync($"/posts/{postId}/comments", cancellationToken);
    }
}

